import React, { useState } from 'react';
import { 
  ShieldCheck, 
  ShieldAlert, 
  ArrowUpRight, 
  ArrowDownLeft, 
  Trash2, 
  Settings2,
  Power,
  Zap,
  Lock,
  Search
} from 'lucide-react';

const FirewallAutomationTool = () => {
  // Rule Mapping: The central data structure for automation logic
  const [rules, setRules] = useState([
    { id: '1', name: 'Inbound HTTPS', port: 443, protocol: 'TCP', direction: 'in', active: true, priority: 100 },
    { id: '2', name: 'SSH Admin Access', port: 22, protocol: 'TCP', direction: 'in', active: false, priority: 200 },
    { id: '3', name: 'API Outbound Call', port: 8080, protocol: 'UDP', direction: 'out', active: true, priority: 300 },
    { id: '4', name: 'Database Egress', port: 5432, protocol: 'TCP', direction: 'out', active: true, priority: 400 },
  ]);

  const toggleRule = (id) => {
    setRules(prev => prev.map(rule => 
      rule.id === id ? { ...rule, active: !rule.active } : rule
    ));
  };

  const deleteRule = (id) => {
    setRules(prev => prev.filter(rule => rule.id !== id));
  };

  return (
    <div className="max-w-4xl mx-auto p-6 bg-slate-50 min-h-screen font-sans">
      {/* Header & Automation Stats */}
      <div className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <div>
          <h1 className="text-2xl font-black text-slate-800 flex items-center gap-2">
            <Zap className="text-amber-500 fill-amber-500" size={24} /> 
            Firewall Automator
          </h1>
          <p className="text-slate-500 text-sm italic">Status: {rules.filter(r => r.active).length} rules currently enforced</p>
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Filter rules..." 
              className="pl-10 pr-4 py-2 bg-slate-100 border-none rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none"
            />
          </div>
          <button className="bg-slate-900 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-slate-800 transition-colors">
            Deploy Changes
          </button>
        </div>
      </div>

      {/* Rules List Mapping */}
      <div className="grid gap-3">
        {rules.map((rule) => (
          <div 
            key={rule.id}
            className={`flex items-center justify-between p-4 rounded-xl border transition-all duration-300 ${
              rule.active 
                ? 'bg-white border-blue-100 shadow-sm' 
                : 'bg-slate-100 border-transparent opacity-60 grayscale-[0.5]'
            }`}
          >
            <div className="flex items-center gap-4">
              {/* Security Icon Logic */}
              <div className={`p-3 rounded-full ${rule.active ? 'bg-green-100 text-green-600' : 'bg-slate-200 text-slate-500'}`}>
                {rule.active ? <ShieldCheck size={20} /> : <ShieldAlert size={20} />}
              </div>

              {/* Rule Info */}
              <div>
                <div className="flex items-center gap-2">
                  <h3 className="font-bold text-slate-700">{rule.name}</h3>
                  <span className="text-[10px] font-mono font-black bg-slate-200 px-1.5 py-0.5 rounded text-slate-600 uppercase">
                    {rule.protocol}
                  </span>
                </div>
                <div className="flex items-center gap-4 mt-1">
                  <span className="flex items-center text-xs font-medium text-slate-500">
                    {rule.direction === 'in' ? (
                      <><ArrowDownLeft size={14} className="mr-1 text-blue-500" /> Inbound</>
                    ) : (
                      <><ArrowUpRight size={14} className="mr-1 text-orange-500" /> Outbound</>
                    )}
                  </span>
                  <span className="text-xs text-slate-400 flex items-center gap-1">
                    <Lock size={12} /> Port {rule.port}
                  </span>
                  <span className="text-xs text-slate-400">Prio: {rule.priority}</span>
                </div>
              </div>
            </div>

            {/* Automation Action Buttons */}
            <div className="flex items-center gap-1">
              <button 
                onClick={() => toggleRule(rule.id)}
                className={`p-2 rounded-lg transition-colors ${
                  rule.active ? 'text-green-600 hover:bg-green-50' : 'text-slate-400 hover:bg-slate-200'
                }`}
                title={rule.active ? 'Disable' : 'Enable'}
              >
                <Power size={20} />
              </button>
              
              <button className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg">
                <Settings2 size={20} />
              </button>
              
              <button 
                onClick={() => deleteRule(rule.id)}
                className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg"
              >
                <Trash2 size={20} />
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Empty State */}
      {rules.length === 0 && (
        <div className="text-center py-20 border-2 border-dashed border-slate-200 rounded-2xl">
          <p className="text-slate-400">No firewall rules defined. Add one to begin automation.</p>
        </div>
      )}
    </div>
  );
};

export default FirewallAutomationTool;